import{_ as o,o as e,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"52. Rotation Allowances","description":"","frontmatter":{"title":"52. Rotation Allowances","eba":"Doctors in Training 2022-2026","topics":["allowances","employment"]},"headers":[],"relativePath":"ebas/doctors-in-training/allowances/52-rotation-allowances.md","filePath":"ebas/doctors-in-training/allowances/52-rotation-allowances.md"}'),r={name:"ebas/doctors-in-training/allowances/52-rotation-allowances.md"};function i(s,t,l,c,p,d){return e(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="_52-rotation-allowances" tabindex="-1">52. Rotation Allowances <a class="header-anchor" href="#_52-rotation-allowances" aria-label="Permalink to &quot;52. Rotation Allowances&quot;">​</a></h1><p><strong>52.1</strong> Location Allowance – When on Rotation</p><p><strong>(a)</strong> A Doctor must be paid a Location Allowance as detailed in <a href="/eba/ebas/doctors-in-training/appendices/2-doctors-in-training-remuneration-allowances-and-deductions.html">Appendix 2</a>, Table 2.3 for each completed week on Rotation, where the Doctor was required to move residence.</p><p><strong>(b)</strong> A Doctor may be required to produce evidence that satisfies a reasonable person (eg a statutory declaration) to substantiate that the Doctor moved residence.</p><p><strong>(c)</strong> The Location Allowance is designed to defray expenses incurred because the Doctor is required to be on Rotation.</p><p><strong>52.2</strong> Travelling Allowances – When on Rotation within Victoria</p><p><strong>(a)</strong> A Doctor rotated to a position at a Rotation Hospital within Victoria must be paid a flat rate Travelling Allowance of $100 as follows:</p><p><strong>(i)</strong> on commencement of the Rotation; and then</p><p><strong>(ii)</strong> once every three weeks over the 13 week period of Rotation for other than Mildura (refer subclause 52.3(a) below for entitlements when on Rotation to Mildura)</p><p><strong>52.3</strong> Mildura</p><p><strong>(a)</strong> In the case of the Doctor being rotated to Mildura, instead of the entitlement described in subclause 52.2 above, the Doctor must receive a return economy class airfare every four weeks of a 13 week Rotation.</p><p><strong>(b)</strong> To be eligible for the Travelling Allowance under subclause 52.3(b) above, the Doctor must undertake the travel to and from the city of the Parent Hospital at the relevant times.</p><p><strong>52.4</strong> Tasmania</p><p><strong>(a)</strong> A Doctor, rotated to a position at a Rotation Hospital in Tasmania as a part of a College Training Program must be reimbursed for the cost of a return economy class airfare undertaken during each three month rotation as follows:</p><p><strong>(i)</strong> at the beginning and end of the Rotation; and</p><p><strong>(ii)</strong> after the first six weeks of the Rotation.</p><p><strong>52.5</strong> Other Australian States</p><p>A Doctor rotated to a position at a Rotation Hospital outside of Victoria but within Australia must be paid a Travelling Allowance equivalent to an economy class return airfare.</p><p><strong>52.6</strong> Overseas</p><p>A Doctor rotated to a position at a Rotation Hospital outside of Australia is entitled to an economy class return airfare for themselves and their spouse and children who, on or about the commencement of the Rotation, also travel to the Doctor’s Rotation locality.</p><p><strong>52.7</strong> Removal Reimbursement – When on Rotation</p><p>A Doctor rotated to a position at a Rotation Hospital located more than 50km from the Parent Hospital for at least six weeks must be reimbursed for the reasonable and actual expenses incurred by the Doctor in the removal of personal belongings to and from the Rotation locality.</p><p>Plain language terms: rotation allowance.</p>',23)])])}const u=o(r,[["render",i]]);export{g as __pageData,u as default};
